from langchain_core.output_parsers import StrOutputParser

REFINE_SYSTEM = "You are a skilled writer. Improve the output by addressing all feedback points."
REFINE_HUMAN = """Task: {task}

Current output:
{current_output}

Feedback to address:
{feedback}

Write an improved version that fixes every issue listed. Output ONLY the
improved content, no explanation."""

refine_llm = ChatOpenAI(model="gpt-4o", temperature=0.3)
refiner_chain = (
    ChatPromptTemplate.from_messages([("system", REFINE_SYSTEM), ("human", REFINE_HUMAN)])
    | refine_llm
    | StrOutputParser()
)

def self_refine(task: str, initial_output: str, max_iterations: int = 3) -> str:
    current = initial_output
    best_output, best_score = current, 0.0

    for i in range(max_iterations):
        critique: CritiqueResult = critic_chain.invoke({"task": task, "output": current})

        if critique.score > best_score:
            best_output, best_score = current, critique.score

        if critique.should_stop:
            break

        feedback_text = "\n".join(f"- {issue}" for issue in critique.issues)
        current = refiner_chain.invoke({
            "task": task,
            "current_output": current,
            "feedback": feedback_text,
        })

    return best_output

from typing import TypedDict
from langgraph.graph import StateGraph, END

class SelfRefineState(TypedDict):
    task: str
    current_output: str
    critique: CritiqueResult | None
    iteration: int
    history: list[dict]  # [{output, score, issues}]

def generate_node(state: SelfRefineState) -> SelfRefineState:
    generate_llm = ChatOpenAI(model="gpt-4o", temperature=0.5)
    output = generate_llm.invoke(state["task"]).content
    return {"current_output": output, "iteration": 0, "history": []}

def critique_node(state: SelfRefineState) -> SelfRefineState:
    critique = critic_chain.invoke({
        "task": state["task"],
        "output": state["current_output"],
    })
    history = state["history"] + [{
        "iteration": state["iteration"],
        "output": state["current_output"],
        "score": critique.score,
        "issues": critique.issues,
    }]
    return {"critique": critique, "history": history}

def refine_node(state: SelfRefineState) -> SelfRefineState:
    feedback = "\n".join(f"- {i}" for i in state["critique"].issues)
    new_output = refiner_chain.invoke({
        "task": state["task"],
        "current_output": state["current_output"],
        "feedback": feedback,
    })
    return {"current_output": new_output, "iteration": state["iteration"] + 1}

def should_stop(state: SelfRefineState) -> str:
    if state["critique"].should_stop or state["iteration"] >= 3:
        return "end"
    return "refine"

graph = StateGraph(SelfRefineState)
graph.add_node("generate", generate_node)
graph.add_node("critique", critique_node)
graph.add_node("refine", refine_node)
graph.set_entry_point("generate")
graph.add_edge("generate", "critique")
graph.add_conditional_edges("critique", should_stop, {"refine": "refine", "end": END})
graph.add_edge("refine", "critique")
app = graph.compile()

from langchain_core.runnables import RunnableParallel

DIMENSIONS = [
    ("correctness", "Check for factual errors, logical flaws, or incorrect code."),
    ("clarity", "Check for unclear phrasing, jargon without explanation, or poor structure."),
    ("completeness", "Check for missing steps, unexplained assumptions, or gaps in coverage."),
]

def make_dimension_critic(dimension: str, instruction: str):
    system = f"You are a {dimension} critic. {instruction} Report only {dimension} issues."
    return (
        ChatPromptTemplate.from_messages([("system", system), ("human", CRITIQUE_HUMAN)])
        | critique_llm.with_structured_output(CritiqueResult)
    )

dimension_critics = {
    dim: make_dimension_critic(dim, instr)
    for dim, instr in DIMENSIONS
}

parallel_critic = RunnableParallel(**dimension_critics)

def multi_aspect_critique(task: str, output: str) -> list[str]:
    results: dict[str, CritiqueResult] = parallel_critic.invoke({
        "task": task, "output": output
    })
    all_issues = []
    for dim, result in results.items():
        for issue in result.issues:
            all_issues.append(f"[{dim.upper()}] {issue}")
    should_stop = all(r.should_stop for r in results.values())
    return all_issues, should_stop

def token_overlap_similarity(a: str, b: str) -> float:
    """Approximate cosine similarity via token overlap (no external deps)."""
    tokens_a = set(a.lower().split())
    tokens_b = set(b.lower().split())
    if not tokens_a or not tokens_b:
        return 0.0
    intersection = len(tokens_a & tokens_b)
    return intersection / (len(tokens_a | tokens_b))

class ConvergenceDetector:
    def __init__(
        self,
        max_issues_to_continue: int = 1,
        similarity_threshold: float = 0.95,
    ):
        self.max_issues = max_issues_to_continue
        self.sim_threshold = similarity_threshold
        self.previous_output: str | None = None

    def should_stop(self, critique: CritiqueResult, current_output: str) -> tuple[bool, str]:
        # LLM signal
        if critique.should_stop:
            return True, "critic_stop"
        # Issue-count heuristic
        if len(critique.issues) <= self.max_issues:
            return True, "minimal_issues"
        # Output-similarity heuristic
        if self.previous_output is not None:
            sim = token_overlap_similarity(self.previous_output, current_output)
            if sim >= self.sim_threshold:
                return True, f"output_converged (similarity={sim:.2f})"
        self.previous_output = current_output
        return False, ""

# Example usage in the loop
detector = ConvergenceDetector()
for i in range(max_iterations):
    critique = critic_chain.invoke({"task": task, "output": current})
    stop, reason = detector.should_stop(critique, current)
    if stop:
        print(f"Stopping at iteration {i}: {reason}")
        break
    current = refiner_chain.invoke({...})
